// Validate input and normalize for downstream nodes.
const body = $input.first().json.body || $input.first().json;

const site_order_id = body.site_order_id;
const triggered_by = body.triggered_by || 'manual';
const triggered_by_detail = body.triggered_by_detail || 'no detail provided';

// Hard validate site_order_id format
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!site_order_id || !uuidRegex.test(site_order_id)) {
  throw new Error(`Invalid or missing site_order_id: ${site_order_id}. Must be UUID.`);
}

const validTriggers = ['manual', 'cron', 'procore_webhook', 'api'];
if (!validTriggers.includes(triggered_by)) {
  throw new Error(`Invalid triggered_by: ${triggered_by}. Must be one of: ${validTriggers.join(', ')}`);
}

return [{
  json: {
    site_order_id,
    triggered_by,
    triggered_by_detail,
    n8n_execution_id: $execution.id,
    n8n_workflow_id: $workflow.id
  }
}];

// Merge validated input + eligibility result into one payload for branching.
const input = $('Validate Input').first().json;
const result = $input.first().json;

return [{
  json: {
    // Echo input
    site_order_id: input.site_order_id,
    triggered_by: input.triggered_by,
    triggered_by_detail: input.triggered_by_detail,
    n8n_execution_id: input.n8n_execution_id,
    n8n_workflow_id: input.n8n_workflow_id,

    // Function output
    is_eligible: result.is_eligible,
    subcontractor_id: result.subcontractor_id,
    ap_integration_type: result.ap_integration_type,
    blocking_alert_count: result.blocking_alert_count || 0,
    blocking_alert_levels: result.blocking_alert_levels || [],
    reason: result.reason
  }
}];

// PROCORE branch: Eligible sub on Procore-wired GC.
// Today this is a STUB that logs the decision but doesn't actually call Procore's payment-release API.
// Replace this with a real Procore HTTP Request node when:
//   1. integration_configs has the Procore client_secret_vault_id wired
//   2. The Procore Payments API endpoint and auth flow are confirmed
//
// For now: returns a structured action result that downstream audit-log can record.

const input = $input.first().json;

return [{
  json: {
    ...input,
    action_taken: 'released_via_procore',
    action_detail: {
      integration: 'procore',
      stub: true,
      stub_reason: 'Procore Payments API integration not yet built. Decision recorded for audit; manual release required.',
      next_step: 'Operator should manually release in Procore until API integration ships.'
    },
    status: 'pending'
  }
}];

// QUICKBOOKS branch: Eligible sub on QB-wired GC.
// Stub for the same reason as Procore - QB integration not yet built.
// First QB customer signing triggers building this branch out properly.

const input = $input.first().json;

return [{
  json: {
    ...input,
    action_taken: 'released_via_quickbooks',
    action_detail: {
      integration: 'quickbooks',
      stub: true,
      stub_reason: 'QuickBooks Payments API integration not yet built. Decision recorded for audit; manual release required.',
      next_step: 'Operator should manually release in QuickBooks until API integration ships.'
    },
    status: 'pending'
  }
}];

// MANUAL branch: Eligible sub but ap_integration_type is 'manual' or NULL.
// Always requires human intervention; not a bug.

const input = $input.first().json;

return [{
  json: {
    ...input,
    action_taken: 'released_manual_review',
    action_detail: {
      integration: 'manual',
      next_step: 'Sub flagged for manual payment release. AP team to action via their normal process.'
    },
    status: 'pending'
  }
}];

// BLOCKED branch: Sub ineligible. Compose the GC alert payload.
// One Slack message per decision. Channel = #bfc-compliance-alerts (where Workflow 1 already posts).

const input = $input.first().json;

const levelsStr = (input.blocking_alert_levels || []).join(', ');

return [{
  json: {
    ...input,
    action_taken: 'blocked_alert_sent',
    action_detail: {
      slack_channel: 'C0B0ZT3P79R',
      message_summary: `Payment blocked for site_order ${input.site_order_id}: sub has ${input.blocking_alert_count} active alert(s) at level(s) ${levelsStr}.`,
      reason: input.reason
    },
    status: 'pending'
  }
}];
